<?php
$renderRows=static function(array $rows,string $type):void{foreach($rows as $item):$collection=$type==='collection';$image=$item['image_path']?:'/assets/images/packaging-reference.png';$edit=$collection?'/admin/colectii/'.$item['id'].'/edit':'/admin/categorii/'.$item['id'].'/edit';$status=$collection?'/admin/colectii/'.$item['id'].'/status':'/admin/categorii/'.$item['id'].'/status';$delete=$collection?'/admin/colectii/'.$item['id'].'/sterge':'/admin/categorii/'.$item['id'].'/sterge';$blocked=!$collection&&((int)$item['product_count']>0||(int)$item['child_count']>0);?>
<tr><td><a class="admin-category-cell" href="<?= e(url($edit)) ?>"><img src="<?= e(url($image)) ?>" alt="" width="58" height="58"><span><strong><?= e($item['name']) ?></strong><small><?= e($item['description']?:'Fără descriere') ?></small></span></a></td><td><?= e($item['slug']) ?></td><?php if(!$collection): ?><td><?= e($item['parent_name']??'—') ?></td><?php endif; ?><td><?= (int)$item['product_count'] ?></td><td><?= (int)($item['sort_order']??0) ?></td><td><form class="admin-category-toggle" method="post" action="<?= e(url($status)) ?>" data-category-toggle><?= csrf_field() ?><input type="hidden" name="is_active" value="0"><label class="admin-switch"><input type="checkbox" name="is_active" value="1" <?= $item['is_active']?'checked':'' ?> data-category-status><span></span></label><small data-category-status-label><?= $item['is_active']?'Vizibilă':'Ascunsă' ?></small></form></td><td><div class="admin-table-actions"><a class="admin-icon-action" href="<?= e(url($edit)) ?>" title="Editează"><svg viewBox="0 0 24 24"><path d="M4 20h4l11-11-4-4L4 16v4zM13.5 6.5l4 4"/></svg></a><form method="post" action="<?= e(url($delete)) ?>" data-confirm-delete data-confirm-message="<?= $collection?'Colecția va fi ștearsă. Produsele asociate vor fi păstrate.':'Categoria va fi arhivată.' ?>"><?= csrf_field() ?><button class="admin-icon-action danger" type="submit" <?= $blocked?'disabled':'' ?>><svg viewBox="0 0 24 24"><path d="M4 7h16M9 7V4h6v3m-9 0 1 13h10l1-13"/></svg></button></form></div></td></tr>
<?php endforeach;};$visibleCollections=count(array_filter($collections,static fn($item)=>(bool)$item['is_active']));?>
<section class="admin-page-head"><div><p class="eyebrow">CATALOG</p><h1>Categorii și colecții</h1><p>Două tipuri distincte de organizare, fără dublări.</p></div><div class="button-row"><a class="admin-button secondary" href="<?= e(url('/admin/categorii/creare')) ?>">+ Categorie</a><a class="admin-button" href="<?= e(url('/admin/colectii/creare')) ?>">+ Colecție</a></div></section>
<section class="admin-panel"><div class="panel-head"><div><p class="eyebrow">SELECȚII EDITORIALE</p><div class="admin-title-with-tooltip"><h2>Colecții</h2><span class="admin-tooltip" tabindex="0">i<span role="tooltip">Se recomandă 4–5 colecții active pentru un homepage echilibrat.</span></span></div><p>Apar în „Colecțiile noastre” și în filtrul Colecții.</p></div><span class="status-pill accent"><?= count($collections) ?> create · <?= $visibleCollections ?> vizibile</span></div><div class="admin-table-wrap"><table class="admin-table"><thead><tr><th>Colecție</th><th>Slug</th><th>Produse</th><th>Ordine</th><th>Pe website</th><th>Acțiuni</th></tr></thead><tbody><?php if($collections):$renderRows($collections,'collection');else:?><tr><td colspan="6" class="admin-empty">Nu există colecții. Creează prima colecție.</td></tr><?php endif;?></tbody></table></div></section>
<section class="admin-panel"><div class="panel-head"><div><p class="eyebrow">STRUCTURA MAGAZINULUI</p><h2>Categorii</h2><p>Organizează produsele și filtrele magazinului.</p></div></div><div class="admin-table-wrap"><table class="admin-table"><thead><tr><th>Categorie</th><th>Slug</th><th>Părinte</th><th>Produse</th><th>Ordine</th><th>Pe website</th><th>Acțiuni</th></tr></thead><tbody><?php if($categories):$renderRows($categories,'category');else:?><tr><td colspan="7" class="admin-empty">Nu există categorii.</td></tr><?php endif;?></tbody></table></div></section>